class LRUCache {
public:
    LRUCache(int capacity) : capacity_(capacity), cache_(capacity, -1) {
        for (int i = 0; i < capacity; i++) {
            cache_[i] = -1;
        }
    }

    int get(int key) {
        if (cache_[key] == -1) {
            return -1;
        }
        int value = cache_[key];
        cache_[key] = -1;
        for (int i = 0; i < capacity_; i++) {
            if (cache_[i] == -1) {
                cache_[i] = key;
                return value;
            }
        }
        return value;
    }

    void put(int key, int value) {
        if (cache_[key] != -1) {
            cache_[key] = -1;
        }
        cache_[key] = value;
        for (int i = 0; i < capacity_; i++) {
            if (cache_[i] == -1) {
                cache_[i] = key;
                return;
            }
        }
    }
private:
    int capacity_;
    vector<int> cache_;
};
```
